// Transform n8n workflows to Boost.space Business Case format
const workflows = $input.all();
const output = [];

for (const workflow of workflows) {
  const data = workflow.json;

  // Build description with metadata
  const descParts = [];
  descParts.push(`n8n ID: ${data.id}`);
  if (data.tags && data.tags.length > 0) {
    descParts.push(`Tags: ${data.tags.map(t => t.name).join(', ')}`);
  }
  descParts.push(`Active: ${data.active ? 'Yes' : 'No'}`);
  descParts.push(`Created: ${new Date(data.createdAt).toLocaleDateString()}`);
  descParts.push(`Updated: ${new Date(data.updatedAt).toLocaleDateString()}`);

  // Map to Business Case structure
  const businessCase = {
    name: data.name || 'Unnamed Workflow',
    description: descParts.join(' | '),
    spaceId: 43, // n8n Workflows space
    status_system_id: data.active ? 1 : 2, // 1=active, 2=inactive
    // Store n8n ID for future updates
    customData: {
      n8nId: data.id,
      n8nActive: data.active
    }
  };

  output.push({ json: businessCase });
}

return output;

// Summary of sync results
const items = $input.all();
const success = items.filter(i => i.json.id).length;
const failed = items.length - success;

return [{
  json: {
    syncTime: new Date().toISOString(),
    totalWorkflows: items.length,
    successful: success,
    failed: failed,
    status: failed === 0 ? 'SUCCESS' : 'PARTIAL'
  }
}];
